//! Codec round-trip property tests + decode-never-panics smoke (M4.6).
//!
//! Spec: `specs/08-platformvm-pchain.md` §11.1; `specs/02-testing-strategy.md`
//! §4, §6, §8.
//!
//! * `pchain_tx_roundtrip` — `decode(encode(x)) == x` for an arbitrary
//!   [`UnsignedTx`] generated by [`arb_unsigned_tx`], which covers **every**
//!   variant. The generated txs carry arbitrary-but-valid field shapes (they are
//!   not required to pass `syntactic_verify`); they only need to round-trip
//!   through the codec byte-for-byte.
//! * `decode_never_panics` — feeds arbitrary `Vec<u8>` to [`Tx::parse`] and
//!   [`Block::parse`], asserting only that decoding never panics. This is the
//!   stable substitute for the cargo-fuzz `decode_block_tx` target (the repo's
//!   fuzz convention: nightly-only `cargo fuzz`, with a stable proptest smoke as
//!   the always-on gate).

#![allow(
    unused_crate_dependencies,
    clippy::unwrap_used,
    clippy::expect_used,
    clippy::indexing_slicing
)]

use proptest::collection::vec;
use proptest::prelude::*;

use ava_platformvm::block::Block;
use ava_platformvm::signer::{
    Empty, PUBLIC_KEY_LEN, ProofOfPossession, SIGNATURE_LEN as BLS_SIGNATURE_LEN, Signer,
};
use ava_platformvm::stakeable::{LockIn, LockOut};
use ava_platformvm::txs::components::{
    Auth, BaseTx as AvaxBaseTx, Input, Output, Owner, PChainOwner, TransferableInput,
    TransferableOutput,
};
use ava_platformvm::txs::{
    self, AddAutoRenewedValidatorTx, AddDelegatorTx, AddPermissionlessDelegatorTx,
    AddPermissionlessValidatorTx, AddSubnetValidatorTx, AddValidatorTx, AdvanceTimeTx, BaseTx,
    ConvertSubnetToL1Tx, ConvertSubnetToL1Validator, CreateChainTx, CreateSubnetTx,
    DisableL1ValidatorTx, ExportTx, ImportTx, IncreaseL1ValidatorBalanceTx, RegisterL1ValidatorTx,
    RemoveSubnetValidatorTx, RewardAutoRenewedValidatorTx, RewardValidatorTx,
    SetAutoRenewedValidatorConfigTx, SetL1ValidatorWeightTx, SubnetValidator,
    TransferSubnetOwnershipTx, TransformSubnetTx, Tx, UnsignedTx, Validator,
};
use ava_secp256k1fx::{Input as Secp256k1Input, OutputOwners, TransferInput, TransferOutput};
use ava_types::id::Id;
use ava_types::node_id::NodeId;
use ava_types::short_id::ShortId;

// BLS proof-of-possession signature length (the `register_l1` PoP, which
// reuses `signer::SIGNATURE_LEN` = the BLS signature length, 96 bytes).
const BLS_PROOF_LEN: usize = BLS_SIGNATURE_LEN;

// Bounded collection sizes keep each generated case cheap.
const MAX_VEC: usize = 3;

// ---------------------------------------------------------------------------
// Leaf strategies
// ---------------------------------------------------------------------------

fn arb_id() -> impl Strategy<Value = Id> {
    any::<[u8; 32]>().prop_map(Id::from)
}

fn arb_node_id() -> impl Strategy<Value = NodeId> {
    any::<[u8; 20]>().prop_map(NodeId::from)
}

fn arb_short_id() -> impl Strategy<Value = ShortId> {
    any::<[u8; 20]>().prop_map(ShortId::from)
}

fn arb_bytes() -> impl Strategy<Value = Vec<u8>> {
    vec(any::<u8>(), 0..=8)
}

fn arb_output_owners() -> impl Strategy<Value = OutputOwners> {
    (any::<u64>(), any::<u32>(), vec(arb_short_id(), 0..=MAX_VEC))
        .prop_map(|(locktime, threshold, addrs)| OutputOwners::new(locktime, threshold, addrs))
}

fn arb_owner() -> impl Strategy<Value = Owner> {
    arb_output_owners().prop_map(Owner::Secp256k1)
}

fn arb_transfer_output() -> impl Strategy<Value = TransferOutput> {
    (any::<u64>(), arb_output_owners()).prop_map(|(amt, owners)| TransferOutput::new(amt, owners))
}

fn arb_transfer_input() -> impl Strategy<Value = TransferInput> {
    (any::<u64>(), vec(any::<u32>(), 0..=MAX_VEC))
        .prop_map(|(amt, sig_indices)| TransferInput::new(amt, sig_indices))
}

fn arb_secp_input() -> impl Strategy<Value = Secp256k1Input> {
    vec(any::<u32>(), 0..=MAX_VEC).prop_map(Secp256k1Input::new)
}

fn arb_auth() -> impl Strategy<Value = Auth> {
    arb_secp_input().prop_map(Auth::Secp256k1)
}

// Output interface: secp256k1fx.TransferOutput (7) or stakeable.LockOut (22).
// LockOut wraps a (non-recursive) TransferOutput to keep generation bounded.
fn arb_output() -> impl Strategy<Value = Output> {
    prop_oneof![
        arb_transfer_output().prop_map(Output::Transfer),
        (any::<u64>(), arb_transfer_output()).prop_map(|(locktime, to)| {
            Output::StakeableLock(LockOut::new(locktime, Output::Transfer(to)))
        }),
    ]
}

// Input interface: secp256k1fx.TransferInput (5) or stakeable.LockIn (21).
fn arb_input() -> impl Strategy<Value = Input> {
    prop_oneof![
        arb_transfer_input().prop_map(Input::Transfer),
        (any::<u64>(), arb_transfer_input()).prop_map(|(locktime, ti)| {
            Input::StakeableLock(LockIn::new(locktime, Input::Transfer(ti)))
        }),
    ]
}

fn arb_transferable_output() -> impl Strategy<Value = TransferableOutput> {
    (arb_id(), arb_output()).prop_map(|(asset_id, out)| TransferableOutput { asset_id, out })
}

fn arb_transferable_input() -> impl Strategy<Value = TransferableInput> {
    (arb_id(), any::<u32>(), arb_id(), arb_input()).prop_map(
        |(tx_id, output_index, asset_id, r#in)| TransferableInput {
            tx_id,
            output_index,
            asset_id,
            r#in,
        },
    )
}

fn arb_avax_base_tx() -> impl Strategy<Value = AvaxBaseTx> {
    (
        any::<u32>(),
        arb_id(),
        vec(arb_transferable_output(), 0..=MAX_VEC),
        vec(arb_transferable_input(), 0..=MAX_VEC),
        arb_bytes(),
    )
        .prop_map(|(network_id, blockchain_id, outs, ins, memo)| AvaxBaseTx {
            network_id,
            blockchain_id,
            outs,
            ins,
            memo,
        })
}

fn arb_base_tx() -> impl Strategy<Value = BaseTx> {
    arb_avax_base_tx().prop_map(BaseTx::new)
}

fn arb_validator() -> impl Strategy<Value = Validator> {
    (arb_node_id(), any::<u64>(), any::<u64>(), any::<u64>()).prop_map(
        |(node_id, start, end, wght)| Validator {
            node_id,
            start,
            end,
            wght,
        },
    )
}

fn arb_subnet_validator() -> impl Strategy<Value = SubnetValidator> {
    (arb_validator(), arb_id())
        .prop_map(|(validator, subnet)| SubnetValidator { validator, subnet })
}

fn arb_proof_of_possession() -> impl Strategy<Value = ProofOfPossession> {
    (
        any::<[u8; PUBLIC_KEY_LEN]>(),
        // 96-byte BLS proof; arrays > 32 have no `Arbitrary`, so build from a vec.
        vec(any::<u8>(), BLS_SIGNATURE_LEN..=BLS_SIGNATURE_LEN),
    )
        .prop_map(|(public_key, proof)| {
            let mut sig = [0u8; BLS_SIGNATURE_LEN];
            sig.copy_from_slice(&proof);
            ProofOfPossession::new(public_key, sig)
        })
}

fn arb_signer() -> impl Strategy<Value = Signer> {
    prop_oneof![
        Just(Signer::Empty(Empty)),
        arb_proof_of_possession().prop_map(Signer::ProofOfPossession),
    ]
}

fn arb_bls_proof() -> impl Strategy<Value = [u8; BLS_PROOF_LEN]> {
    vec(any::<u8>(), BLS_PROOF_LEN..=BLS_PROOF_LEN).prop_map(|v| {
        let mut sig = [0u8; BLS_PROOF_LEN];
        sig.copy_from_slice(&v);
        sig
    })
}

fn arb_pchain_owner() -> impl Strategy<Value = PChainOwner> {
    (any::<u32>(), vec(arb_short_id(), 0..=MAX_VEC)).prop_map(|(threshold, addresses)| {
        PChainOwner {
            threshold,
            addresses,
        }
    })
}

