// ---------------------------------------------------------------------------
// The UnsignedTx union strategy — covers EVERY variant.
// ---------------------------------------------------------------------------

/// A proptest [`Strategy`] generating every [`UnsignedTx`] variant with
/// arbitrary-but-valid field shapes. The result only needs to round-trip through
/// the codec; it is **not** required to pass `syntactic_verify`.
fn arb_unsigned_tx() -> impl Strategy<Value = UnsignedTx> {
    // `prop_oneof!` is limited in arity, so the variants are split into two
    // groups and unioned. Every variant of `UnsignedTx` appears exactly once.
    let group_a = prop_oneof![
        arb_add_validator().prop_map(UnsignedTx::AddValidator),
        arb_add_subnet_validator().prop_map(UnsignedTx::AddSubnetValidator),
        arb_add_delegator().prop_map(UnsignedTx::AddDelegator),
        arb_create_chain().prop_map(UnsignedTx::CreateChain),
        arb_create_subnet().prop_map(UnsignedTx::CreateSubnet),
        arb_import().prop_map(UnsignedTx::Import),
        arb_export().prop_map(UnsignedTx::Export),
        arb_advance_time().prop_map(UnsignedTx::AdvanceTime),
        arb_reward_validator().prop_map(UnsignedTx::RewardValidator),
        arb_remove_subnet_validator().prop_map(UnsignedTx::RemoveSubnetValidator),
        arb_transform_subnet().prop_map(UnsignedTx::TransformSubnet),
        arb_add_permissionless_validator().prop_map(UnsignedTx::AddPermissionlessValidator),
    ];
    let group_b = prop_oneof![
        arb_add_permissionless_delegator().prop_map(UnsignedTx::AddPermissionlessDelegator),
        arb_transfer_subnet_ownership().prop_map(UnsignedTx::TransferSubnetOwnership),
        arb_base().prop_map(UnsignedTx::Base),
        arb_convert_subnet_to_l1().prop_map(UnsignedTx::ConvertSubnetToL1),
        arb_register_l1_validator().prop_map(UnsignedTx::RegisterL1Validator),
        arb_set_l1_validator_weight().prop_map(UnsignedTx::SetL1ValidatorWeight),
        arb_increase_l1_validator_balance().prop_map(UnsignedTx::IncreaseL1ValidatorBalance),
        arb_disable_l1_validator().prop_map(UnsignedTx::DisableL1Validator),
        arb_add_auto_renewed_validator().prop_map(UnsignedTx::AddAutoRenewedValidator),
        arb_set_auto_renewed_validator_config().prop_map(UnsignedTx::SetAutoRenewedValidatorConfig),
        arb_reward_auto_renewed_validator().prop_map(UnsignedTx::RewardAutoRenewedValidator),
    ];
    prop_oneof![group_a, group_b]
}

proptest! {
    // The plan calls for 4096 cases; 1024 keeps CI fast while still exercising
    // every variant many times over (`prop::pchain_tx_roundtrip`).
    #![proptest_config(ProptestConfig::with_cases(1024))]

    /// `decode(encode(x)) == x` for an arbitrary [`UnsignedTx`] (every variant).
    #[test]
    fn pchain_tx_roundtrip(unsigned in arb_unsigned_tx()) {
        let c = txs::codec::codec().expect("build codec");
        let encoded = c
            .marshal(ava_platformvm::CODEC_VERSION, &unsigned)
            .expect("marshal");

        let mut decoded = UnsignedTx::default();
        c.unmarshal(&encoded, &mut decoded).expect("unmarshal");
        prop_assert_eq!(&decoded, &unsigned, "decode(encode(x)) == x");

        // Byte-stability: re-encoding the decoded value reproduces the bytes.
        let reencoded = c
            .marshal(ava_platformvm::CODEC_VERSION, &decoded)
            .expect("re-marshal");
        prop_assert_eq!(reencoded, encoded, "encode(decode(encode(x))) == encode(x)");
    }

    /// A signed [`Tx`] (unsigned body, no creds) also round-trips through
    /// `Tx::initialize`/`Tx::parse`.
    #[test]
    fn pchain_signed_tx_roundtrip(unsigned in arb_unsigned_tx()) {
        let c = txs::codec::codec().expect("build codec");
        let mut tx = Tx::new(unsigned);
        tx.initialize(&c).expect("initialize");
        let parsed = Tx::parse(&c, tx.bytes()).expect("parse");
        prop_assert_eq!(&parsed.unsigned, &tx.unsigned, "signed tx round-trip");
        prop_assert_eq!(parsed.id(), tx.id(), "tx_id round-trip");
    }

    /// Decode-never-panics: arbitrary bytes through the signed-tx and block
    /// parsers never panic (errors are expected and ignored). This is the stable
    /// substitute for the cargo-fuzz `decode_block_tx` target (`specs/02` §8).
    #[test]
    fn decode_never_panics(data in vec(any::<u8>(), 0..=512)) {
        let _ = Tx::parse(txs::Codec(), &data);
        let _ = Block::parse(txs::Codec(), &data);
    }
}
